export function getIllinoisHormoneClinicsByCity(citySlug: string): HormoneClinic[] {
  return illinoisHormoneClinics.filter(c => c.citySlug === citySlug);
}

export function getIllinoisHormoneCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of illinoisHormoneClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
